INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("リリ", 125801, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 40011, 321, 1, 1, 0, 24001, 1, 2);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("クリア", 126001, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 40011, 322, 1, 1, 0, 24001, 2, 2);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("プレシア", 126101, "んーと。\nこれ、あげる。\nはい", 40011, 323, 1, 1, 0, 24001, 3, 2);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("リリ", 125801, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 40011, 324, 2, 1, 0, 24001, 4, 2);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("クリア", 126001, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 40011, 325, 2, 1, 0, 24001, 5, 2);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("プレシア", 126101, "お兄。\nきてくれて、うれしい", 40011, 326, 2, 1, 0, 24001, 6, 2);
